mapper.update:
UPDATE qr_code_queue
SET status = #{status}, updated_time = NOW()
WHERE data_id = #{dataId}

UPDATE qr_code_queue
SET queue_type = 2, status = 4, fail_reason = #{failReason}, updated_time = NOW()
WHERE data_id = #{dataId}

mapper.select:
SELECT COUNT(*)
FROM qr_code_queue
WHERE queue_type = #{queueType} AND status = #{status}

mapper.update:
UPDATE qr_code_current_processing
SET refresh_count = #{refreshCount}, updated_time = NOW()
WHERE data_id = #{dataId}

mapper.delete:
DELETE FROM qr_code_queue
WHERE status = 3
  AND created_time < #{cutoffDate}
